def namespaced_test_name(base: str) -> str:
    namespace = os.environ.get("WORKERCTL_TEST_NAMESPACE")
    if not namespace:
        return base
    safe = "".join(char if char.isalnum() or char in "-_" else "-" for char in namespace)
    return f"{base}-{safe}"[:64]


class CoreRunTests(unittest.TestCase):
    def test_tmux_permission_failure_gets_actionable_message(self):
        def fake_run(argv, **kwargs):
            return subprocess.CompletedProcess(argv, 1, "", "Operation not permitted\n")

        with mock.patch("workerctl.core.subprocess.run", side_effect=fake_run):
            with self.assertRaisesRegex(WorkerError, "tmux access was denied"):
                worker_core.run(["tmux", "new-session", "-d", "-s", "blocked"])

        with mock.patch("workerctl.core.subprocess.run", side_effect=fake_run):
            try:
                worker_core.run(["tmux", "new-session", "-d", "-s", "blocked"])
            except WorkerError as exc:
                self.assertIn("Privacy & Security", str(exc))
                self.assertIn("Operation not permitted", str(exc))


class RalphLoopPresetTests(unittest.TestCase):
    def test_ralph_loop_presets_include_operator_ready_templates(self):
        from workerctl.ralph_loop_presets import list_ralph_loop_presets, ralph_loop_preset_metadata

        names = [preset["name"] for preset in list_ralph_loop_presets()]

        self.assertIn("test_coverage_loop", names)
        self.assertIn("build_then_clear", names)
        self.assertIn("pr_ci_merge_loop", names)
        self.assertIn("compact_then_continue", names)

        coverage = ralph_loop_preset_metadata("test_coverage_loop")
        self.assertEqual(coverage["kind"], "ralph_loop")
        self.assertEqual(coverage["required_before_continue"], ["test_coverage", "adversarial_check"])
        self.assertEqual(coverage["stop_conditions"], ["max_iterations", "required_evidence"])

    def test_ralph_loop_preset_metadata_allows_safe_overrides(self):
        from workerctl.ralph_loop_presets import ralph_loop_preset_metadata

        metadata = ralph_loop_preset_metadata(
            "pr_ci_merge_loop",
            max_iterations=4,
            current_iteration=1,
            seed_prompt_sha256="abc123",
        )

        self.assertEqual(metadata["max_iterations"], 4)
        self.assertEqual(metadata["current_iteration"], 1)
        self.assertEqual(metadata["seed_prompt_sha256"], "abc123")
        self.assertEqual(metadata["required_before_continue"], ["pr_url", "ci_green", "merge", "adversarial_check"])

    def test_ralph_loop_preset_rejects_unknown_name(self):
        from workerctl.ralph_loop_presets import ralph_loop_preset_metadata

        with self.assertRaisesRegex(WorkerError, "Unknown Ralph loop preset"):
            ralph_loop_preset_metadata("not-a-preset")

    def test_loop_templates_include_visual_diff_template(self):
        from workerctl.loop_templates import list_loop_templates, loop_template_metadata

        names = [template["name"] for template in list_loop_templates()]

        self.assertIn("test_coverage_loop", names)
        self.assertIn("pr_ci_merge_loop", names)
        self.assertIn("visual_diff_loop", names)

        visual = loop_template_metadata("visual_diff_loop")
        self.assertEqual(visual["kind"], "ralph_loop")
        self.assertEqual(visual["template"], "visual_diff_loop")
        self.assertEqual(visual["preset"], "visual_diff_loop")
        self.assertEqual(
            visual["required_before_continue"],
            [
                "reference_artifact",
                "candidate_screenshot",
                "visual_diff_report",
                "diff_below_threshold",
                "adversarial_check",
            ],
        )
        self.assertEqual(visual["stop_conditions"], ["max_iterations", "required_evidence", "manager_accepts"])
        self.assertEqual(visual["artifact_requirements"]["diff_score"]["type"], "number")

    def test_quality_loop_templates_require_adversarial_check(self):
        from workerctl.loop_templates import list_loop_templates

        templates = {template["name"]: template for template in list_loop_templates()}

        for name in ("pr_ci_merge_loop", "test_coverage_loop", "visual_diff_loop"):
            with self.subTest(name=name):
                self.assertIn("adversarial_check", templates[name]["required_before_continue"])
                self.assertIn("adversarial_check", templates[name]["artifact_requirements"])
                requirement = templates[name]["artifact_requirements"]["adversarial_check"]
                self.assertEqual(requirement["type"], "object")
                self.assertEqual(requirement["required"], ["failure_mode", "check", "result"])
                self.assertEqual(
                    sorted(requirement["properties"]),
                    ["check", "failure_mode", "result"],
                )

        for name in ("build_then_clear", "compact_then_continue"):
            with self.subTest(name=name):
                self.assertNotIn("adversarial_check", templates[name]["required_before_continue"])
                self.assertNotIn("adversarial_check", templates[name]["artifact_requirements"])

    def test_loop_template_metadata_allows_visual_diff_overrides(self):
        from workerctl.loop_templates import loop_template_metadata

        metadata = loop_template_metadata(
            "visual_diff_loop",
            max_iterations=5,
            current_iteration=2,
            seed_prompt_sha256="visual-seed",
        )

        self.assertEqual(metadata["max_iterations"], 5)
        self.assertEqual(metadata["current_iteration"], 2)
        self.assertEqual(metadata["seed_prompt_sha256"], "visual-seed")
        self.assertEqual(metadata["cleanup_policy"], "compact")
        self.assertEqual(metadata["template"], "visual_diff_loop")

    def test_loop_template_outputs_are_mutation_safe(self):
        from workerctl.loop_templates import list_loop_templates, loop_template_metadata

        metadata = loop_template_metadata("visual_diff_loop")
        metadata["artifact_requirements"]["diff_score"]["type"] = "mutated"

        fresh_metadata = loop_template_metadata("visual_diff_loop")

        self.assertEqual(fresh_metadata["artifact_requirements"]["diff_score"]["type"], "number")

        summary = next(template for template in list_loop_templates() if template["name"] == "visual_diff_loop")
        summary["artifact_requirements"]["diff_score"]["type"] = "mutated-again"

        fresh_summary = next(template for template in list_loop_templates() if template["name"] == "visual_diff_loop")

        self.assertEqual(fresh_summary["artifact_requirements"]["diff_score"]["type"], "number")

    def test_adversarial_check_requirement_is_not_shared_between_templates(self):
        from copy import deepcopy

        from workerctl.loop_templates import list_loop_templates, loop_template, loop_template_metadata

        quality_template_names = ("pr_ci_merge_loop", "test_coverage_loop", "visual_diff_loop")
        templates = {name: loop_template(name) for name in quality_template_names}
        originals = {
            name: deepcopy(templates[name].artifact_requirements["adversarial_check"])
            for name in quality_template_names
        }
        try:
            templates["pr_ci_merge_loop"].artifact_requirements["adversarial_check"]["required"].append("leaked_field")
            templates["pr_ci_merge_loop"].artifact_requirements["adversarial_check"]["properties"]["leaked_field"] = {
                "type": "string"
            }

            visual_metadata = loop_template_metadata("visual_diff_loop")
            coverage_summary = next(
                template for template in list_loop_templates() if template["name"] == "test_coverage_loop"
            )

            self.assertEqual(
                visual_metadata["artifact_requirements"]["adversarial_check"]["required"],
                ["failure_mode", "check", "result"],
            )
            self.assertNotIn(
                "leaked_field",
                visual_metadata["artifact_requirements"]["adversarial_check"]["properties"],
            )
            self.assertEqual(
                coverage_summary["artifact_requirements"]["adversarial_check"]["required"],
                ["failure_mode", "check", "result"],
            )
            self.assertNotIn(
                "leaked_field",
                coverage_summary["artifact_requirements"]["adversarial_check"]["properties"],
            )
        finally:
            for name, original in originals.items():
                templates[name].artifact_requirements["adversarial_check"] = original


class DatabaseTests(unittest.TestCase):
    def open_db(self, tmpdir):
        path = Path(tmpdir) / "workerctl.db"
        conn = worker_db.connect(path)
        worker_db.initialize_database(conn)
        self.addCleanup(conn.close)
        return conn

    def insert_worker(self, conn, worker_id="worker-1", name="worker-a"):
        now = "2026-05-08T10:00:00Z"
        conn.execute(
            """
            insert into workers(
              id, name, tmux_session, identity_token, cwd, state, created_at, updated_at
            )
            values (?, ?, ?, ?, ?, 'candidate', ?, ?)
            """,
            (worker_id, name, f"codex-{name}", f"token-{worker_id}", str(ROOT), now, now),
        )

    def insert_task(self, conn, task_id="task-1", name="task-a"):
        now = "2026-05-08T10:00:00Z"
        conn.execute(
            """
            insert into tasks(id, name, goal, state, created_at, updated_at)
            values (?, ?, 'goal', 'candidate', ?, ?)
            """,
            (task_id, name, now, now),
        )

    def test_database_initializes_schema_and_pragmas(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            conn = self.open_db(tmpdir)

            foreign_keys = conn.execute("PRAGMA foreign_keys").fetchone()[0]
            busy_timeout = conn.execute("PRAGMA busy_timeout").fetchone()[0]
            version = conn.execute("select max(version) from schema_migrations").fetchone()[0]
            user_version = conn.execute("PRAGMA user_version").fetchone()[0]

            self.assertEqual(foreign_keys, 1)
            self.assertEqual(busy_timeout, 5000)
            self.assertEqual(version, worker_db.SCHEMA_VERSION)
            self.assertEqual(user_version, worker_db.SCHEMA_VERSION)

            tables = {
                row["name"]
                for row in conn.execute("select name from sqlite_master where type = 'table'")
            }
            indexes = {
                row["name"]
                for row in conn.execute("select name from sqlite_master where type = 'index'")
            }
            self.assertIn("runs", tables)
            self.assertIn("telemetry_events", tables)
            self.assertIn("telemetry_events_fts", tables)
            self.assertIn("command_attempts", tables)
            self.assertIn("manager_cycle_spans", tables)
            self.assertIn("one_active_run_per_task", indexes)
            self.assertIn("telemetry_events_run_timestamp", indexes)
            self.assertIn("commands_claimable", indexes)
            self.assertIn("command_attempts_command_id", indexes)
            self.assertIn("manager_cycle_spans_cycle_phase", indexes)
            self.assertIn("manager_cycle_spans_task", indexes)

    def test_database_migrates_pre_dispatch_command_schema(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            path = Path(tmpdir) / "workerctl.db"
            conn = sqlite3.connect(path)
            conn.executescript(
                """
                create table commands(
                  id text primary key,
                  idempotency_key text unique not null,
                  created_at text not null,
                  updated_at text not null,
                  task_id text,
                  worker_id text,
                  manager_id text,
                  type text not null,
                  state text not null,
                  payload_json text not null check (json_valid(payload_json)),
                  result_json text check (result_json is null or json_valid(result_json)),
                  error text
                );
                pragma user_version = 15;
                """
            )
            conn.close()

            conn = worker_db.connect(path)
            self.addCleanup(conn.close)
            worker_db.initialize_database(conn)
            columns = {row["name"] for row in conn.execute("pragma table_info(commands)")}
            indexes = {
                row["name"]
                for row in conn.execute("select name from sqlite_master where type = 'index'")
            }

            self.assertIn("available_at", columns)
            self.assertIn("claim_expires_at", columns)
            self.assertIn("required_permission", columns)
            self.assertIn("commands_claimable", indexes)
            self.assertEqual(conn.execute("PRAGMA user_version").fetchone()[0], worker_db.SCHEMA_VERSION)

