    def test_command_attempt_finish_records_side_effect_flags_and_replay(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            conn = self.open_db(tmpdir)
            self.insert_task(conn, "task-attempt", "attempt-task")
            command_id = worker_db.create_command(
                conn,
                command_type="notify_manager",
                task_id="task-attempt",
                payload={"message": "hello"},
            )
            claimed = worker_db.claim_next_dispatch_command(
                conn,
                dispatcher_id="dispatch-a",
                command_types=["notify_manager"],
                timestamp="2026-05-23T10:01:00Z",
            )
            worker_db.finish_command_attempt(
                conn,
                attempt_id=claimed["attempt"]["id"],
                state="abandoned",
                result={"reason": "deferred"},
                error="deferred",
                side_effect_started=False,
                side_effect_completed=False,
                timestamp="2026-05-23T10:01:01Z",
            )
            conn.commit()

            row = conn.execute("select state, error from commands where id = ?", (command_id,)).fetchone()
            self.assertEqual(row["state"], "failed")
            self.assertEqual(row["error"], "deferred")
            audit = worker_db.task_audit(conn, task="attempt-task")
            self.assertEqual(audit["command_attempts"][0]["state"], "abandoned")
            entries = replay.replay_entries(audit)
            self.assertTrue(any(entry["source"] == "command_attempts" for entry in entries))

    def test_command_attempt_finish_requires_running_attempt(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            conn = self.open_db(tmpdir)
            self.insert_task(conn, "task-attempt", "attempt-task")
            command_id = worker_db.create_command(
                conn,
                command_type="notify_manager",
                task_id="task-attempt",
                payload={"message": "hello"},
            )
            claimed = worker_db.claim_next_dispatch_command(
                conn,
                dispatcher_id="dispatch-a",
                command_types=["notify_manager"],
                timestamp="2026-05-23T10:01:00Z",
            )
            worker_db.finish_command_attempt(
                conn,
                attempt_id=claimed["attempt"]["id"],
                state="succeeded",
                result={"ok": True},
                timestamp="2026-05-23T10:01:01Z",
            )

            with self.assertRaises(WorkerError):
                worker_db.finish_command_attempt(
                    conn,
                    attempt_id=claimed["attempt"]["id"],
                    state="failed",
                    error="late failure",
                    timestamp="2026-05-23T10:01:02Z",
                )

            command_row = conn.execute("select state, error from commands where id = ?", (command_id,)).fetchone()
            attempt_row = conn.execute("select state, error from command_attempts where id = ?", (claimed["attempt"]["id"],)).fetchone()
            telemetry = [
                event for event in worker_db.telemetry_events(conn, task_id="task-attempt")
                if event["event_type"] in {"dispatch_command_succeeded", "dispatch_command_failed"}
            ]
            self.assertEqual(command_row["state"], "succeeded")
            self.assertIsNone(command_row["error"])
            self.assertEqual(attempt_row["state"], "succeeded")
            self.assertIsNone(attempt_row["error"])
            self.assertEqual([event["event_type"] for event in telemetry], ["dispatch_command_succeeded"])

    def test_telemetry_event_helpers_attach_active_run_and_index_search_text(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            conn = self.open_db(tmpdir)
            task_id = worker_db.create_task(conn, name="telemetry-task", goal="Observe QA.")
            run_id = worker_db.create_run(conn, task_id=task_id, name="telemetry-run")

            event_id = worker_db.emit_telemetry_event(
                conn,
                task_id=task_id,
                actor="manager",
                event_type="manager_nudge",
                severity="info",
                summary="Manager nudged worker after stale output.",
                correlation={"cycle_id": 7},
                attributes={"reason": "stale output"},
            )

            events = worker_db.telemetry_events(conn, run_id=run_id)
            self.assertEqual(len(events), 1)
            self.assertEqual(events[0]["id"], event_id)
            self.assertEqual(events[0]["run_id"], run_id)
            self.assertEqual(events[0]["correlation"], {"cycle_id": 7})
            self.assertEqual(events[0]["attributes"], {"reason": "stale output"})
            search = conn.execute(
                """
                select event_id
                from telemetry_events_fts
                where telemetry_events_fts match 'stale'
                """
            ).fetchone()
            self.assertEqual(search["event_id"], event_id)
            hyphen_search = worker_db.query_telemetry_events(conn, search="stale-output")
            self.assertEqual([event["id"] for event in hyphen_search], [event_id])

    def test_telemetry_event_helpers_validate_inputs_before_insert(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            conn = self.open_db(tmpdir)
            task_id = worker_db.create_task(conn, name="telemetry-validation", goal="Validate telemetry.")
            other_task_id = worker_db.create_task(conn, name="other-task", goal="Other task.")
            run_id = worker_db.create_run(conn, task_id=task_id, name="validation-run")

            invalid_cases = [
                (
                    {"task_id": task_id, "actor": "human", "summary": "Bad actor."},
                    "invalid telemetry actor",
                ),
                (
                    {"task_id": task_id, "actor": "workerctl", "severity": "fatal", "summary": "Bad severity."},
                    "invalid telemetry severity",
                ),
                (
                    {"task_id": task_id, "actor": "workerctl", "summary": "Bad correlation.", "correlation": []},
                    "telemetry correlation must be a JSON object",
                ),
                (
                    {"task_id": task_id, "actor": "workerctl", "summary": "Bad attributes.", "attributes": []},
                    "telemetry attributes must be a JSON object",
                ),
                (
                    {"task_id": "missing-task", "actor": "workerctl", "summary": "Missing task."},
                    "Unknown task id",
                ),
                (
                    {"run_id": "missing-run", "actor": "workerctl", "summary": "Missing run."},
                    "Unknown run",
                ),
                (
                    {"run_id": run_id, "task_id": other_task_id, "actor": "workerctl", "summary": "Mismatch."},
                    "does not match run",
                ),
            ]

            for kwargs, message in invalid_cases:
                with self.subTest(message=message):
                    with self.assertRaisesRegex(WorkerError, message):
                        worker_db.emit_telemetry_event(conn, event_type="validation_failed", **kwargs)

            self.assertEqual(conn.execute("select count(*) from telemetry_events").fetchone()[0], 0)
            self.assertEqual(conn.execute("select count(*) from telemetry_events_fts").fetchone()[0], 0)

