class DispatchTests(unittest.TestCase):
    def open_db(self, tmpdir):
        path = Path(tmpdir) / "workerctl.db"
        conn = worker_db.connect(path)
        worker_db.initialize_database(conn)
        self.addCleanup(conn.close)
        return conn, path

    def setup_bound_task(self, conn):
        now = "2026-05-23T10:00:00Z"
        conn.execute(
            "insert into tasks(id, name, goal, state, created_at, updated_at) "
            "values ('task-dispatch', 'dispatch-task', 'Route completion.', 'managed', ?, ?)",
            (now, now),
        )
        worker_id = worker_db.register_session(
            conn,
            name="worker-session",
            role="worker",
            codex_session_path="/tmp/worker.jsonl",
            codex_session_id="codex-worker",
            pid=11,
            cwd="/repo",
            tmux_session="tmux-worker",
        )
        manager_id = worker_db.register_session(
            conn,
            name="manager-session",
            role="manager",
            codex_session_path="/tmp/manager.jsonl",
            codex_session_id="codex-manager",
            pid=12,
            cwd="/repo",
            tmux_session="tmux-manager",
        )
        worker_db.bind_sessions(
            conn,
            task_name="dispatch-task",
            worker_session_name="worker-session",
            manager_session_name="manager-session",
        )
        conn.commit()
        return worker_id, manager_id

    def create_visual_diff_template_loop_run(self, conn):
        from workerctl.loop_templates import loop_template_metadata

        metadata = loop_template_metadata("visual_diff_loop", current_iteration=1)
        return worker_db.create_ralph_loop_run(
            conn,
            task_id="task-dispatch",
            name="visual-loop",
            max_iterations=metadata["max_iterations"],
            current_iteration=metadata["current_iteration"],
            cleanup_policy=metadata.get("cleanup_policy"),
            required_before_continue=metadata.get("required_before_continue"),
            stop_conditions=metadata.get("stop_conditions"),
            seed_prompt_sha256=metadata.get("seed_prompt_sha256"),
            preset=metadata.get("preset"),
            metadata=metadata,
        )

    def write_test_png(self, path: Path, pixels: list[tuple[int, int, int, int]]) -> None:
        width = len(pixels)
        height = 1

        def chunk(kind: bytes, payload: bytes) -> bytes:
            checksum = zlib.crc32(kind + payload) & 0xFFFFFFFF
            return struct.pack(">I", len(payload)) + kind + payload + struct.pack(">I", checksum)

        raw = b"\x00" + b"".join(bytes(pixel) for pixel in pixels)
        path.write_bytes(
            b"\x89PNG\r\n\x1a\n"
            + chunk(b"IHDR", struct.pack(">IIBBBBB", width, height, 8, 6, 0, 0, 0))
            + chunk(b"IDAT", zlib.compress(raw))
            + chunk(b"IEND", b"")
        )

    def insert_completion(
        self,
        conn,
        session_id,
        *,
        offset=1,
        timestamp="2026-05-23T10:01:00Z",
        payload=None,
    ):
        return worker_db.insert_codex_event(
            conn,
            session_id=session_id,
            timestamp=timestamp,
            event_type="message",
            subtype="task_complete",
            payload=payload or {"msg": "done"},
            byte_offset=offset,
        )

    def test_dispatch_once_routes_worker_completion_to_bound_manager(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            conn, db_path = self.open_db(tmpdir)
            worker_id, manager_id = self.setup_bound_task(conn)
            event_id = self.insert_completion(
                conn,
                worker_id,
                payload={
                    "last_agent_message": "pytest passed; diff is focused",
                    "turn_id": "turn-dispatch",
                },
            )
            conn.commit()

            sent = []

            def fake_send(conn, *, session_name, text, dry_run=False, side_effect_audit=None, side_effect_started_callback=None):
                sent.append({"session_name": session_name, "text": text, "dry_run": dry_run})
                return {"target": "tmux-manager:0.0"}

            args = argparse.Namespace(
                dispatcher_id="dispatch-test",
                dry_run=False,
                json=True,
                limit=10,
                once=True,
                path=str(db_path),
                type=None,
                watch=False,
            )
            with mock.patch.object(worker_tmux, "send_text_to_session", side_effect=fake_send):
                with contextlib.redirect_stdout(io.StringIO()) as stdout:
                    result = commands.command_dispatch(args)

            payload = json.loads(stdout.getvalue())
            notifications = worker_db.routed_notifications(conn, task_id="task-dispatch")
            telemetry = worker_db.telemetry_events(conn, task_id="task-dispatch")

            self.assertEqual(result, 0)
            self.assertEqual(payload["processed_count"], 1)
            self.assertEqual(sent[0]["session_name"], "manager-session")
            self.assertIn("appears to have completed a turn", sent[0]["text"])
            self.assertEqual(notifications[0]["state"], "delivered")
            self.assertEqual(notifications[0]["source_event_id"], event_id)
            self.assertIn(str(event_id), notifications[0]["dedupe_key"])
            self.assertEqual(
                notifications[0]["payload"]["worker_receipt"]["last_agent_message"],
                "pytest passed; diff is focused",
            )
            self.assertEqual(
                notifications[0]["payload"]["worker_receipt"]["turn_id"],
                "turn-dispatch",
            )
            self.assertTrue(notifications[0]["correlation_id"].startswith("dispatch-"))
            self.assertIn("dispatch_signal_detected", [event["event_type"] for event in telemetry])
            self.assertIn("dispatch_signal_routed", [event["event_type"] for event in telemetry])

    def test_dispatch_completion_to_no_tmux_manager_creates_pull_required_inbox_item(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            conn, db_path = self.open_db(tmpdir)
            worker_id, manager_id = self.setup_bound_task(conn)
            conn.execute("update sessions set tmux_session = null where id = ?", (manager_id,))
            event_id = self.insert_completion(conn, worker_id)
            conn.commit()

            args = argparse.Namespace(
                dispatcher_id="dispatch-test",
                dry_run=False,
                json=True,
                limit=10,
                once=True,
                path=str(db_path),
                type=None,
                watch=False,
            )
            with mock.patch.object(worker_tmux, "send_text_to_session") as send:
                with contextlib.redirect_stdout(io.StringIO()) as stdout:
                    result = commands.command_dispatch(args)

            payload = json.loads(stdout.getvalue())
            notification = worker_db.routed_notifications(conn, task_id="task-dispatch")[0]
            inbox = worker_db.session_inbox(conn, session_name="manager-session")
            telemetry = worker_db.telemetry_events(conn, task_id="task-dispatch")

            self.assertEqual(result, 0)
            self.assertEqual(payload["processed"][0]["state"], "pull_required")
            self.assertEqual(notification["state"], "delivered")
            self.assertEqual(notification["delivery_mode"], "pull_required")
            self.assertFalse(notification["side_effect_started"])
            self.assertFalse(notification["side_effect_completed"])
            self.assertEqual(notification["source_event_id"], event_id)
            self.assertEqual([item["id"] for item in inbox], [notification["id"]])
            self.assertIn("dispatch_signal_pull_required", [event["event_type"] for event in telemetry])
            send.assert_not_called()

    def test_dispatch_completion_notification_has_correlation_chain(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            conn, db_path = self.open_db(tmpdir)
            worker_id, manager_id = self.setup_bound_task(conn)
            event_id = self.insert_completion(conn, worker_id)
            conn.commit()

            args = argparse.Namespace(
                dispatcher_id="dispatch-test",
                dry_run=False,
                json=True,
                limit=10,
                once=True,
                path=str(db_path),
                type=None,
                watch=False,
            )
            with mock.patch.object(worker_tmux, "send_text_to_session", return_value={"target": "tmux-manager:0.0"}):
                with contextlib.redirect_stdout(io.StringIO()):
                    commands.command_dispatch(args)

            conn.execute(
                """
                insert into manager_cycles(task_id, started_at, completed_at, state, status_json)
                values ('task-dispatch', '9999-01-01T00:00:00Z', '9999-01-01T00:00:01Z', 'succeeded', '{}')
                """
            )
            cycle_id = conn.execute("select id from manager_cycles").fetchone()["id"]
            notifications = worker_db.routed_notifications(conn, task_id="task-dispatch")
            worker_db.consume_routed_notifications_for_cycle(
                conn,
                task_id="task-dispatch",
                binding_id=notifications[0]["binding_id"],
                manager_cycle_id=cycle_id,
                timestamp="9999-01-01T00:00:00Z",
            )
            decision_id = worker_db.insert_manager_decision(
                conn,
                task_id="task-dispatch",
                manager_id=None,
                manager_cycle_id=cycle_id,
                decision="inspect",
                reason="inspect routed worker completion",
            )
            conn.commit()

            audit = worker_db.task_audit(conn, task="dispatch-task")
            chain = audit["correlation_chains"][0]
            notification = worker_db.routed_notifications(conn, task_id="task-dispatch")[0]
            self.assertIsNone(chain["command_id"])
            self.assertEqual(chain["correlation_id"], notification["correlation_id"])
            self.assertEqual(chain["created_at"], notification["created_at"])
            self.assertEqual(chain["manager_cycle_id"], cycle_id)
            self.assertEqual(chain["manager_decision_id"], decision_id)
            self.assertEqual(chain["signal_type"], "worker_task_complete")
            self.assertEqual(chain["source_event_id"], event_id)
            self.assertEqual(chain["routed_notification_ids"], [notification["id"]])
            replay_entries = replay.replay_entries(audit)
            chain_entry = next(entry for entry in replay_entries if entry["source"] == "correlation_chains")
            self.assertEqual(chain_entry["source_id"], notification["correlation_id"])
            self.assertEqual(chain_entry["timestamp"], notification["created_at"])
            self.assertIn(f"source event #{event_id}", chain_entry["summary"])

    def test_dispatch_completion_correlation_uses_consumed_cycle_not_next_cycle_heuristic(self):
        from workerctl import supervise_cycle

        with tempfile.TemporaryDirectory() as tmpdir:
            conn, db_path = self.open_db(tmpdir)
            worker_id, manager_id = self.setup_bound_task(conn)
            rollout = Path(tmpdir) / "worker.jsonl"
            rollout.write_text(json.dumps({"type": "session_meta", "payload": {"id": "codex-worker"}}) + "\n")
            conn.execute(
                "update sessions set codex_session_path = ? where id = ?",
                (str(rollout), worker_id),
            )
            binding_id = conn.execute(
                "select id from bindings where task_id = 'task-dispatch'"
            ).fetchone()["id"]
            event_id = self.insert_completion(conn, worker_id, timestamp="2026-05-23T10:01:00Z")
            notification_id = worker_db.insert_routed_notification(
                conn,
                task_id="task-dispatch",
                binding_id=binding_id,
                correlation_id="dispatch-consume",
                source_session_id=worker_id,
                target_session_id=manager_id,
                signal_type="worker_task_complete",
                source_event_id=event_id,
                source_event_timestamp="2026-05-23T10:01:00Z",
                dedupe_key=f"{binding_id}:worker_task_complete:{worker_id}:{event_id}",
                payload={"message": "inspect"},
                state="delivered",
                timestamp="2026-05-23T10:01:30Z",
            )
            decoy_cycle_id = worker_db.create_manager_cycle(
                conn,
                task_id="task-dispatch",
                manager_id=None,
                timestamp="2026-05-23T10:02:00Z",
            )
            worker_db.finish_manager_cycle(
                conn,
                cycle_id=decoy_cycle_id,
                state="succeeded",
                status={"kind": "session_cycle", "task": "dispatch-task"},
                timestamp="2026-05-23T10:02:01Z",
            )
            worker_db.insert_manager_decision(
                conn,
                task_id="task-dispatch",
                manager_id=None,
                manager_cycle_id=decoy_cycle_id,
                decision="inspect",
                reason="decoy cycle should not consume notification",
            )
            conn.commit()

            with mock.patch.object(supervise_cycle, "_pid_is_alive", return_value=True):
                result = supervise_cycle.run_cycle(
                    conn,
                    task_name="dispatch-task",
                    now="2026-05-23T10:03:00Z",
                )

            audit = worker_db.task_audit(conn, task="dispatch-task")
            chain = next(
                chain
                for chain in audit["correlation_chains"]
                if chain["routed_notification_ids"] == [notification_id]
            )
            self.assertEqual(chain["manager_cycle_id"], result["cycle_id"])
            self.assertNotEqual(chain["manager_cycle_id"], decoy_cycle_id)

