class ClassifierTests(unittest.TestCase):
    def test_startup_detects_trust_prompt(self):
        state, reason = classify.classify_startup_output(
            "Do you trust the contents of this directory?\nPress enter to continue"
        )

        self.assertEqual(state, "needs_trust")
        self.assertIn("trust", reason.lower())

    def test_startup_detects_ready_prompt(self):
        state, reason = classify.classify_startup_output("OpenAI Codex\n\n› Implement {feature}")

        self.assertEqual(state, "ready")
        self.assertIn("input prompt", reason)

    def test_busy_wait_detects_mcp_startup_when_status_is_stale(self):
        result = classify.classify_busy_wait(
            "Starting MCP servers (2/3): posthog (1m 25s esc to interrupt)",
            status_age=120,
            busy_wait_seconds=60,
        )

        self.assertIsNotNone(result)
        self.assertEqual(result["pattern"], "mcp_startup")
        self.assertEqual(result["recommended_action"], "inspect_or_interrupt")

    def test_busy_wait_ignores_mcp_startup_when_status_is_fresh(self):
        result = classify.classify_busy_wait(
            "Starting MCP servers (2/3): posthog",
            status_age=10,
            busy_wait_seconds=60,
        )

        self.assertIsNone(result)

    def test_busy_wait_detects_rate_limit_prompt(self):
        result = classify.classify_busy_wait(
            "Approaching rate limits\nSwitch to gpt-5.4-mini?\nPress enter to confirm",
            status_age=120,
            busy_wait_seconds=60,
        )

        self.assertIsNotNone(result)
        self.assertEqual(result["pattern"], "rate_limit_prompt")

    def test_busy_wait_detects_plan_prompt(self):
        result = classify.classify_busy_wait(
            "Create a plan? shift + tab use Plan mode esc dismiss",
            status_age=120,
            busy_wait_seconds=60,
        )

        self.assertIsNotNone(result)
        self.assertEqual(result["pattern"], "plan_prompt")

    def test_busy_wait_ignores_historical_approval_prompt_transcript_text(self):
        result = classify.classify_busy_wait(
            "\n".join(
                [
                    "Earlier cycle summary:",
                    "notable_pane_pattern: approval_prompt",
                    "recommended_action: inspect_or_approve",
                    "The worker is continuing normal implementation now.",
                    "No active prompt is waiting at the bottom of the pane.",
                ]
            ),
            status_age=120,
            busy_wait_seconds=60,
        )

        self.assertIsNone(result)

    def test_busy_wait_detects_active_approval_prompt(self):
        result = classify.classify_busy_wait(
            "\n".join(
                [
                    "Command requires approval before continuing.",
                    "Allow command to run?",
                    "1. Yes, allow",
                    "2. No, deny",
                ]
            ),
            status_age=120,
            busy_wait_seconds=60,
        )

        self.assertIsNotNone(result)
        self.assertEqual(result["pattern"], "approval_prompt")
        self.assertEqual(result["recommended_action"], "inspect_or_approve")

    def test_classifier_suppresses_long_running_interruptible_with_recent_events(self):
        # status_age high (would normally trigger long_running_interruptible),
        # but recent_event_count is also high — worker is healthy, suppress flag.
        result = classify.classify_busy_wait(
            "running tests... esc to interrupt",
            status_age=300,
            busy_wait_seconds=60,
            recent_event_count=133,
        )
        # With high recent_event_count, the pattern should be suppressed (None).
        self.assertIsNone(result)

    def test_classifier_still_flags_long_running_interruptible_when_event_count_low(self):
        result = classify.classify_busy_wait(
            "running tests... esc to interrupt",
            status_age=300,
            busy_wait_seconds=60,
            recent_event_count=2,
        )
        self.assertEqual(result.get("pattern"), "long_running_interruptible")


class LiveSmokeScriptTests(unittest.TestCase):
    def assert_script_uses_existing_workerctl_subcommands(self, script_name):
        parser = worker_cli.build_parser()
        subparser_action = next(
            action for action in parser._actions if isinstance(action, argparse._SubParsersAction)
        )
        subcommands = set(subparser_action.choices)
        script = (ROOT / "scripts" / script_name).read_text()

        used = set()
        for line in script.splitlines():
            stripped = line.strip().rstrip("\\").strip()
            if not stripped or stripped.startswith("#"):
                continue
            try:
                parts = shlex.split(stripped, comments=True, posix=True)
            except ValueError:
                continue
            workerctl_tokens = {"workerctl", "${WORKERCTL}", "$WORKERCTL", str(WORKERCTL_PATH)}
            indexes = [index for index, part in enumerate(parts) if part in workerctl_tokens]
            if not indexes:
                continue
            index = indexes[0]
            if index + 1 < len(parts):
                candidate = parts[index + 1]
                if candidate and not candidate.startswith("-"):
                    used.add(candidate)

        self.assertTrue(used)
        missing = sorted(command for command in used if command not in subcommands)
        self.assertEqual([], missing)

    def test_live_smoke_uses_existing_workerctl_subcommands(self):
        self.assert_script_uses_existing_workerctl_subcommands("live-smoke")

    def test_live_smoke_repeat_uses_existing_workerctl_subcommands(self):
        self.assert_script_uses_existing_workerctl_subcommands("live-smoke-repeat")


class WarningGateScriptTests(unittest.TestCase):
    def test_warning_gate_passes_clean_command(self):
        proc = subprocess.run(
            [str(ROOT / "scripts" / "check-resource-warnings"), "--", sys.executable, "-c", "print('clean')"],
            cwd=ROOT,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False,
        )

        self.assertEqual(proc.returncode, 0, proc.stderr)
        self.assertIn("clean", proc.stdout)

    def test_warning_gate_fails_on_finalizer_output(self):
        code = "open('/dev/null')"
        proc = subprocess.run(
            [
                str(ROOT / "scripts" / "check-resource-warnings"),
                "--",
                sys.executable,
                "-W",
                "always::ResourceWarning",
                "-c",
                code,
            ],
            cwd=ROOT,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False,
        )

        self.assertEqual(proc.returncode, 1)
        self.assertIn("ResourceWarning detected", proc.stderr)


class CliTests(unittest.TestCase):
    def run_workerctl(self, *args, via_shim=False):
        command = [str(WORKERCTL_SHIM_PATH), *args] if via_shim else [sys.executable, str(WORKERCTL_PATH), *args]
        return subprocess.run(
            command,
            cwd=ROOT,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False,
        )

    def run_codex_review_helper(self, *args, env=None):
        merged_env = os.environ.copy()
        for key in (
            "CODEX_REVIEW_ALLOW_NESTED",
            "CODEX_REVIEW_HELPER_LEVEL",
            "CODEX_REVIEW_HELPER_PARENT_PID",
            "CODEX_REVIEW_OUTPUT",
            "CODEX_BIN",
        ):
            merged_env.pop(key, None)
        if env:
            merged_env.update(env)
        return subprocess.run(
            [str(CODEX_REVIEW_HELPER_PATH), *args],
            cwd=ROOT,
            env=merged_env,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False,
        )

    def write_codex_rollout(self, directory: str, session_id: str) -> Path:
        rollout = Path(directory) / f"rollout-{session_id}.jsonl"
        rollout.write_text(
            json.dumps({"type": "session_meta", "payload": {"id": session_id, "cwd": directory}}) + "\n"
        )
        return rollout

