    def test_current_state_walks_back_to_most_recent_state_event(self):
        from workerctl import ingest

        with tempfile.TemporaryDirectory() as tmpdir:
            path = Path(tmpdir) / "workerctl.db"
            conn = worker_db.connect(path)
