    def test_request_worker_compact_dry_run_requires_policy_handoff_and_decision(self):
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = self._setup_db(tmpdir)
            conn = worker_db.connect(db_path)
            try:
                task_id = worker_db.create_task(conn, name="compact-task", goal="Do config.")
                worker_db.register_session(
                    conn,
                    name="compact-worker",
                    role="worker",
                    codex_session_path="/tmp/worker.jsonl",
                    codex_session_id="worker-session",
                    pid=123,
                    cwd=tmpdir,
                    tmux_session="codex-compact-worker",
                )
                worker_db.register_session(
                    conn,
                    name="compact-manager",
                    role="manager",
                    codex_session_path="/tmp/manager.jsonl",
                    codex_session_id="manager-session",
                    pid=124,
                    cwd=tmpdir,
                    tmux_session="codex-compact-manager",
                )
                worker_db.bind_sessions(
                    conn,
                    task_name="compact-task",
                    worker_session_name="compact-worker",
                    manager_session_name="compact-manager",
                )
                worker_db.upsert_manager_config(
                    conn,
                    task_id=task_id,
                    supervision_mode="guided",
                    permissions={"worker_compact_clear": True},
                )
                handoff_id = worker_db.insert_worker_handoff(
                    conn,
                    task_id=task_id,
                    summary="Ready to compact.",
                )
                cycle_id = worker_db.create_manager_cycle(
                    conn,
                    task_id=task_id,
                    manager_id=None,
                    timestamp="2026-05-20T00:00:00Z",
                )
                decision_id = worker_db.insert_manager_decision(
                    conn,
                    task_id=task_id,
                    manager_id=None,
                    manager_cycle_id=cycle_id,
                    decision="nudge",
                    reason="Request worker compaction after handoff.",
                )
                conn.commit()
            finally:
                conn.close()

            proc = subprocess.run(
                [
                    sys.executable,
                    "-m",
                    "workerctl",
                    "request-worker-compact",
                    "compact-task",
                    "--decision-id",
                    str(decision_id),
                    "--strict-decisions",
                    "--dry-run",
                    "--path",
                    str(db_path),
                ],
                capture_output=True,
                text=True,
                cwd=str(ROOT),
            )

            self.assertEqual(proc.returncode, 0, proc.stderr)
            payload = json.loads(proc.stdout)
            self.assertEqual(payload["permission_check"]["handoff_id"], handoff_id)
            self.assertTrue(payload["permission_check"]["allowed"])
            self.assertEqual(payload["send_result"]["session"], "compact-worker")
            self.assertTrue(payload["send_result"]["dry_run"])
            self.assertEqual(payload["slash_command"], "/compact")
            self.assertEqual(payload["send_text"], "/compact")
            self.assertEqual(payload["send_result"]["text"], "/compact")
            self.assertIn("verify the saved handoff", payload["message"])

            conn = worker_db.connect(db_path)
            try:
                audit = worker_db.task_audit(conn, task="compact-task")
                command = [row for row in audit["commands"] if row["type"] == "request_worker_compact"][0]
                self.assertEqual(command["state"], "succeeded")
                events = [row["type"] for row in audit["events"]]
                self.assertIn("worker_compact_requested", events)
                self.assertIn("worker_compact_request_succeeded", events)
                telemetry = worker_db.telemetry_events(conn, task_id=task_id)
                telemetry_types = [event["event_type"] for event in telemetry]
                self.assertIn("manager_permission_checked", telemetry_types)
                self.assertIn("command_created", telemetry_types)
                self.assertIn("command_attempted", telemetry_types)
                self.assertIn("command_succeeded", telemetry_types)
                command_event = next(
                    event for event in telemetry
                    if event["event_type"] == "command_succeeded"
                )
                self.assertEqual(command_event["correlation"]["command_id"], command["id"])
                self.assertEqual(command_event["attributes"]["result"]["worker_session"], "compact-worker")
                spans = worker_db.manager_cycle_spans(conn, manager_cycle_id=cycle_id)
                side_effect_span = next(span for span in spans if span["phase"] == "side_effect_command")
                self.assertEqual(side_effect_span["command_id"], command["id"])
                self.assertEqual(side_effect_span["manager_decision_id"], decision_id)
                self.assertEqual(side_effect_span["attributes"]["command_type"], "request_worker_compact")
            finally:
                conn.close()

            mutation_proc = subprocess.run(
                [
                    sys.executable,
                    "-m",
                    "workerctl",
                    "mutation-audit",
                    "compact-task",
                    "--json",
                    "--path",
                    str(db_path),
                ],
                capture_output=True,
                text=True,
                cwd=str(ROOT),
            )

            self.assertEqual(mutation_proc.returncode, 0, mutation_proc.stderr)
            mutation_payload = json.loads(mutation_proc.stdout)
            self.assertTrue(mutation_payload["ok"])
            self.assertEqual(mutation_payload["summary"]["mutations"], 1)
            record = mutation_payload["records"][0]
            self.assertEqual(record["command"]["type"], "request_worker_compact")
            self.assertEqual(record["linked_decision"]["id"], decision_id)
            self.assertTrue(record["effect"]["dry_run"])
            self.assertFalse(record["effect"]["sent"])
            self.assertEqual(record["effect"]["slash_command"], "/compact")
            self.assertEqual(record["effect"]["send_text"], "/compact")
            self.assertEqual(record["effect"]["worker_session"], "compact-worker")
            self.assertTrue(record["effect"]["permission_check"]["allowed"])

